app.use((err, req, res, next) => {
  console.error(err.stack); // Log internally
  res.status(err.status || 500).json({
    error: 'Internal Server Error' // Never expose err.message in production
  });
});
```

---

### 3. 🟠 No 404 Handler

Unmatched routes currently fall through silently. Add a catch-all:

```js
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});
```

---

### 4. 🟠 Missing Security Headers

Use the `helmet` middleware to set secure HTTP headers (CSP, HSTS, X-Frame-Options, etc.):

```js
const helmet = require('helmet');
app.use(helmet());
```

---

### 5. 🟠 No Rate Limiting

The `/users` endpoint (and especially any auth endpoints you add) should be rate-limited:

```js
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);
```

---

### 6. 🟡 `/users` Endpoint Exposes All Data with No Pagination or Filtering

In a real app, unbounded data dumps are a risk. Consider:
- Adding a query parameter whitelist (validate and sanitize any `?filter=` or `?id=` params)
- Enforcing pagination (`?page=1&limit=20`) with max-limit caps

```js
