  try {
    const page = Math.max(1, parseInt(req.query.page, 10) || 1);
    const limit = Math.min(100, parseInt(req.query.limit, 10) || 20);
    // ... fetch paginated data
    res.json({ data: users, page, limit });
  } catch (err) {
    next(err); // Pass errors to centralized handler
  }
});
```

---

